#include <stdio.h>

int main() {
    int a = 15, b = 4;
    printf("a + b = %d\n", a + b);
    printf("a - b = %d\n", a - b);
    printf("a * b = %d\n", a * b);
    printf("a / b = %d\n", a / b);
    printf("a % b = %d\n", a % b);
    return 0;
}

#include <stdio.h>

int main() {
    int x, y;
    printf("Enter x and y: ");
    scanf("%d %d", &x, &y);
    printf("x > y is %d\n", x > y);
    return 0;
}

#include <stdio.h>

int main() {
    int num;
    printf("Enter a number: ");
    scanf("%d", &num);
    if (num >= 10 && num <= 20) {
        printf("In range\n");
    } else {
        printf("Out of range\n");
    }
    return 0;
}

#include <stdio.h>

int main() {
    int i = 5;
    printf("Original: %d\n", i);
    printf("Pre-increment: %d\n", ++i); // Increases, then prints 6
    printf("Post-increment: %d\n", i++); // Prints 6, then increases
    printf("Final: %d\n", i); // Prints 7
    return 0;
}

#include <stdio.h>

int main() {
    int a = 10, b = 20;
    int max = (a > b) ? a : b;
    printf("Max: %d\n", max);
    return 0;
}

#include <stdio.h>

int main() {
    int result = 5 + 3 * 2;
    printf("Result: %d\n", result);
    return 0;
}

#include <stdio.h>

int main() {
    int x;
    printf("sizeof(int): %lu\n", sizeof(int));
    printf("sizeof(x): %lu\n", sizeof(x));
    return 0;
}

#include <stdio.h>

int main() {
    int a = 5, b = 2;
    float result = (float)a / b;
    printf("Result: %.1f\n", result);
    return 0;
}

#include <stdio.h>

int main() {
    int zero = 0;
    printf("~0 = %d\n", ~zero);
    return 0;
}
